#include <stdio.h>

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, idx, val;
        scanf("%d", &N);
        int arr[20]; // N <= 15, extra space for insertion
        for(int i=0;i<N;i++) scanf("%d", &arr[i]);
        scanf("%d", &idx);
        scanf("%d", &val);
        // shift right
        for(int i=N;i>idx;i--) arr[i]=arr[i-1];
        arr[idx]=val;
        for(int i=0;i<=N;i++){
            if(i) printf(" ");
            printf("%d", arr[i]);
        }
        if(T) printf("\n");
    }
    return 0;
}

