const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let pos = 0;
const T = input[pos++];
let results = [];
for(let t=0; t<T; t++){
  const N = input[pos++];
  let arr = input.slice(pos, pos+N);
  pos += N;
  const idx = input[pos++];
  const val = input[pos++];
  arr.push(0); // extra space
  for(let i=N; i>idx; i--){
    arr[i] = arr[i-1];
  }
  arr[idx] = val;
  results.push(arr.slice(0, N+1).join(' '));
}
console.log(results.join('\n'));

